const results = items[0].json.results || [];

// Pegar último id_unico, data e lista de id_unicos existentes (vêm do fluxo via Code in JavaScript1)
let ultimoIdUnico = null;
let ultimaData = null;
let idUnicosExistentesArray = [];
try {
  const prev = $('Code in JavaScript1').first().json;
  ultimoIdUnico = prev.ultimoIdUnico || null;
  ultimaData = prev.ultimaData || null;
  idUnicosExistentesArray = Array.isArray(prev.idUnicosExistentes) ? prev.idUnicosExistentes : [];
} catch (e) {
  // Se não conseguir pegar, tenta buscar diretamente do Get many rows
  try {
    const todasTransacoes = $('Get many rows').all();
    todasTransacoes.forEach(item => {
      if (item.json && item.json.id_unico) {
        idUnicosExistentesArray.push(String(item.json.id_unico));
      }
    });
  } catch (e2) {}
}

// Se ainda não tem nada e tem ultimoIdUnico, adiciona ele
if (idUnicosExistentesArray.length === 0 && ultimoIdUnico) {
  idUnicosExistentesArray.push(String(ultimoIdUnico));
}

// Converter array para Set para busca rápida
const idUnicosExistentes = new Set(idUnicosExistentesArray.map(id => String(id).trim()));

// Função auxiliar para gerar id_unico no mesmo formato da tabela
// Formato na tabela: "2026-02-12T02:55:28.000Z-PESSOA-VALOR"
function gerarIdUnico(rawDate, pessoa, amount) {
  // Se rawDate já tem timestamp completo, usa ele; senão, usa só a data
  if (rawDate && typeof rawDate === 'string' && rawDate.includes('T')) {
    // Já tem timestamp completo (ex: "2026-02-12T02:55:28.000Z")
    return `${rawDate}-${pessoa}-${amount}`;
  } else {
    // Só tem data (ex: "2026-02-12"), usa como está
    return `${rawDate || ''}-${pessoa}-${amount}`;
  }
}

// Filtrar: não incluir transações que já estão na tabela
const resultsFiltrados = results.filter(r => {
  const rawDate = r.date || r.dateCreated;
  const date = rawDate && typeof rawDate === 'string' && rawDate.includes('T') ? rawDate.split('T')[0] : rawDate;
  const pessoa = (r.description || r.merchantName || r.paymentData?.payer?.name || 'Transação sem descrição').trim();
  const amount = Math.abs(parseFloat(r.amount) || 0);

  // Gerar id_unico no mesmo formato da tabela (com timestamp completo se disponível)
  const id_unico = gerarIdUnico(rawDate, pessoa, amount);
  const id_unicoNormalizado = String(id_unico).trim();

  // Excluir se já existe na tabela (por id_unico) - verificação principal
  if (idUnicosExistentes.has(id_unicoNormalizado)) {
    return false;
  }

  // Verificar também sem normalização (caso o Set tenha valores diferentes)
  for (const existente of idUnicosExistentes) {
    if (String(existente).trim() === id_unicoNormalizado) {
      return false;
    }
  }

  // Excluir se for exatamente a última transação (backup check)
  if (ultimoIdUnico && id_unicoNormalizado === String(ultimoIdUnico).trim()) {
    return false;
  }

  // Excluir apenas se a data for ANTERIOR à última (não igual, para pegar transações do mesmo dia)
  if (ultimaData && date < ultimaData) {
    return false;
  }

  return true;
});

return resultsFiltrados.map(r => {
  const rawDate = r.date || r.dateCreated;
  const date = rawDate && typeof rawDate === 'string' && rawDate.includes('T') ? rawDate.split('T')[0] : rawDate;
  const pessoa = (r.description || r.merchantName || r.paymentData?.payer?.name || 'Transação sem descrição').trim();
  const paymentMethod = r.paymentData?.paymentMethod ?? '';
  const descricao = paymentMethod;
  const amount = Math.abs(parseFloat(r.amount) || 0);
  const originalAmount = parseFloat(r.amount) || 0;
  const tipo = originalAmount >= 0 ? 'entrada' : 'saida';

  // Gerar id_unico no mesmo formato da tabela (com timestamp completo se disponível)
  const id_unico = gerarIdUnico(rawDate, pessoa, amount);

  return {
    json: {
      data: date,
      descricao: descricao || '',
      valor: amount,
      tipo: tipo || 'saida',
      pessoa: pessoa || '',
      id_unico: id_unico,
      categoria: paymentMethod || ''
    }
  };
});

const input = $input.item.json;

// Pegar apiKey - pode vir como string ou objeto
let apiKey = input.apiKey;
if (typeof apiKey === 'object' && apiKey !== null) {
  apiKey = apiKey.token || apiKey.apiKey || JSON.stringify(apiKey);
}
apiKey = String(apiKey || '');

// Remover caracteres inválidos para headers (newline, tab, aspas, etc)
const cleanApiKey = String(apiKey || '').replace(/[\r\n\t"'\x00]/g, '').trim();
// Pegar itemId
const itemId = input.itemId || input.id || '';

// Pegar accountId
const accountId = input.accountId || input.id || '';

// Pegar datas e informações da última transação do node "Pegar última data"
let fromDate = input.fromDate;
let toDate = input.toDate;
let ultimoIdUnico = input.ultimoIdUnico || null;
let ultimaData = input.ultimaData || null;
let idUnicosExistentes = input.idUnicosExistentes || [];

if (!fromDate || !toDate) {
  try {
    const datasNode = $('Pegar última data').item.json;
    fromDate = datasNode.fromDate || fromDate;
    toDate = datasNode.toDate || toDate;
    ultimoIdUnico = datasNode.ultimoIdUnico || ultimoIdUnico;
    ultimaData = datasNode.ultimaData || ultimaData;
    idUnicosExistentes = datasNode.idUnicosExistentes || idUnicosExistentes;
  } catch (e) {
    const hoje = new Date();
    const trintaDiasAtras = new Date();
    trintaDiasAtras.setDate(hoje.getDate() - 30);
    fromDate = fromDate || trintaDiasAtras.toISOString().split('T')[0];
    toDate = toDate || hoje.toISOString().split('T')[0];
  }
}

  if (!fromDate || !toDate) {
    const hoje = new Date();
    const trintaDiasAtras = new Date();
    trintaDiasAtras.setDate(hoje.getDate() - 30);
    fromDate = fromDate || trintaDiasAtras.toISOString().split('T')[0];
    toDate = toDate || hoje.toISOString().split('T')[0];
  }

return {
  json: {
    apiKey: cleanApiKey,
    itemId: itemId,
    accountId: accountId,
    fromDate: fromDate,
    toDate: toDate,
    ultimoIdUnico: ultimoIdUnico,
    ultimaData: ultimaData,
    idUnicosExistentes: idUnicosExistentes
  }
};

const items = $input.all();

// Se não tem transações (tabela vazia), usa últimos 30 dias
if (items.length === 0) {
  const hoje = new Date();
  const trintaDiasAtras = new Date();
  trintaDiasAtras.setDate(hoje.getDate() - 30);

  return {
    json: {
      fromDate: trintaDiasAtras.toISOString().split('T')[0],
      toDate: hoje.toISOString().split('T')[0],
      ultimaData: null,
      ultimoIdUnico: null,
      idUnicosExistentes: []
    }
  };
}

// Coletar TODOS os id_unicos existentes na tabela
const idUnicosExistentes = [];
items.forEach(item => {
  if (item.json && item.json.id_unico) {
    idUnicosExistentes.push(String(item.json.id_unico));
  }
});

// Ordena por data (mais recente primeiro), depois por id_unico para garantir ordem
const sorted = items.sort((a, b) => {
  const dateA = new Date(a.json.data || 0);
  const dateB = new Date(b.json.data || 0);
  if (dateB.getTime() !== dateA.getTime()) {
    return dateB - dateA;
  }
  // Se mesma data, ordena por id_unico (mais recente primeiro)
  return (b.json.id_unico || '').localeCompare(a.json.id_unico || '');
});

// Pega a data da mais recente
const ultimaDataStr = sorted[0].json.data;
const ultimoIdUnico = sorted[0].json.id_unico || null;
const ultimaData = ultimaDataStr;

const hoje = new Date();
const hojeStr = hoje.toISOString().split('T')[0];

// fromDate = dia seguinte à última transação (para não repetir)
// Mas se a última transação é de hoje, usa hoje mesmo (para pegar todas de hoje)
const lastDate = new Date(ultimaDataStr);
let fromDate;
if (ultimaDataStr === hojeStr) {
  // Se a última transação é de hoje, busca desde hoje (para pegar todas de hoje)
  fromDate = hojeStr;
} else {
  // Se a última transação é de outro dia, busca do dia seguinte
  lastDate.setDate(lastDate.getDate() + 1);
  fromDate = lastDate.toISOString().split('T')[0];
}

const toDate = hojeStr;

return {
  json: {
    fromDate: fromDate,
    toDate: toDate,
    ultimaData: ultimaData,
    ultimoIdUnico: ultimoIdUnico,
    idUnicosExistentes: idUnicosExistentes
  }
};

const hoje = new Date();
const trintaDiasAtras = new Date();
trintaDiasAtras.setDate(hoje.getDate() - 30);

return {
  json: {
    fromDate: trintaDiasAtras.toISOString().split('T')[0] + 'T00:00:00.000Z',
    toDate: hoje.toISOString().split('T')[0] + 'T23:59:59.999Z'
  }
};
